def _cassandra_view_to_nested(cassandra_view: CassandraView) -> CassandraViewNested:
    """Convert flat CassandraView to nested format."""
    attrs = CassandraViewAttributes()
    _populate_cassandra_view_attrs(attrs, cassandra_view)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        cassandra_view, _CASSANDRA_VIEW_REL_FIELDS, CassandraViewRelationshipAttributes
    )
    return CassandraViewNested(
        guid=cassandra_view.guid,
        type_name=cassandra_view.type_name,
        status=cassandra_view.status,
        version=cassandra_view.version,
        create_time=cassandra_view.create_time,
        update_time=cassandra_view.update_time,
        created_by=cassandra_view.created_by,
        updated_by=cassandra_view.updated_by,
        classifications=cassandra_view.classifications,
        classification_names=cassandra_view.classification_names,
        meanings=cassandra_view.meanings,
        labels=cassandra_view.labels,
        business_attributes=cassandra_view.business_attributes,
        custom_attributes=cassandra_view.custom_attributes,
        pending_tasks=cassandra_view.pending_tasks,
        proxy=cassandra_view.proxy,
        is_incomplete=cassandra_view.is_incomplete,
        provenance_type=cassandra_view.provenance_type,
        home_id=cassandra_view.home_id,
        depth=cassandra_view.depth,
        immediate_upstream=cassandra_view.immediate_upstream,
        immediate_downstream=cassandra_view.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _cassandra_view_from_nested(nested: CassandraViewNested) -> CassandraView:
    """Convert nested format to flat CassandraView."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else CassandraViewAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _CASSANDRA_VIEW_REL_FIELDS,
        CassandraViewRelationshipAttributes,
    )
    return CassandraView(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_cassandra_view_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _cassandra_view_to_nested_bytes(
    cassandra_view: CassandraView, serde: Serde
) -> bytes:
    """Convert flat CassandraView to nested JSON bytes."""
    return serde.encode(_cassandra_view_to_nested(cassandra_view))


def _cassandra_view_from_nested_bytes(data: bytes, serde: Serde) -> CassandraView:
    """Convert nested JSON bytes to flat CassandraView."""
    nested = serde.decode(data, CassandraViewNested)
    return _cassandra_view_from_nested(nested)


